const CLOCK_TOLERANCE = 30; // seconds

// Middleware to validate OAuth 2.0 Bearer tokens
function validateAccessToken(req, res, next) {
    const authHeader = req.headers.authorization;
    
    if (!authHeader) {
        return res.status(401).json({ 
            error: 'invalid_request',
            error_description: 'Missing Authorization header' 
        });
    }

    const parts = authHeader.split(' ');
    
    if (parts.length !== 2) {
        return res.status(401).json({ 
            error: 'invalid_request',
            error_description: 'Invalid Authorization header format' 
        });
    }

    const [scheme, token] = parts;
    
    if (!/^Bearer$/i.test(scheme)) {
        return res.status(401).json({ 
            error: 'invalid_request',
            error_description: 'Authorization scheme must be Bearer' 
        });
    }

    if (!token || token.trim() === '') {
        return res.status(401).json({ 
            error: 'invalid_token',
            error_description: 'Token is missing' 
        });
    }

    try {
        const decoded = jwt.verify(token, JWT_PUBLIC_KEY, {
            algorithms: ALLOWED_ALGORITHMS,
            issuer: ISSUER,
            audience: AUDIENCE,
            clockTolerance: CLOCK_TOLERANCE,
            complete: false
        });

        if (!decoded.sub) {
            return res.status(401).json({ 
                error: 'invalid_token',
                error_description: 'Token missing required subject claim' 
            });
        }

        if (!decoded.exp) {
            return res.status(401).json({ 
                error: 'invalid_token',
                error_description: 'Token missing expiration claim' 
            });
        }

        if (decoded.scope) {
            decoded.scopes = typeof decoded.scope === 'string' 
                ? decoded.scope.split(' ') 
                : decoded.scope;
        } else {
            decoded.scopes = [];
        }

        req.user = {
            sub: decoded.sub,
            scopes: decoded.scopes,
            claims: decoded
        };

        next();
    } catch (error) {
        if (error.name === 'TokenExpiredError') {
            return res.status(401).json({ 
                error: 'invalid_token',
                error_description: 'Token has expired' 
            });
        } else if (error.name === 'JsonWebTokenError') {
            return res.status(401).json({ 
                error: 'invalid_token',
                error_description: 'Token signature verification failed' 
            });
        } else if (error.name === 'NotBeforeError') {
            return res.status(401).json({ 
                error: 'invalid_token',
                error_description: 'Token not yet valid' 
            });
        } else {
            return res.status(401).json({ 
                error: 'invalid_token',
                error_description: 'Token validation failed' 
            });
        }
    }
}

// Middleware to check required scopes
function requireScopes(...requiredScopes) {
    return (req, res, next) => {
        if (!req.user) {
            return res.status(401).json({ 
                error: 'invalid_token',
                error_description: 'No authenticated user' 
            });
        }

        const userScopes = req.user.scopes || [];
        const hasRequiredScopes = requiredScopes.every(scope => 
            userScopes.includes(scope)
        );

        if (!hasRequiredScopes) {
            return res.status(403).json({ 
                error: 'insufficient_scope',
                error_description: 'Token does not have required scopes',
                scope: requiredScopes.join(' ')
            });
        }

        next();
    };
}

